const month = Number(formData.月份 || 0);
const district = String(formData.区域 || '');
const prevMonth = month === 1 ? 12 : month - 1;
const prevYear = month === 1 ? year - 1 : year;
const rows = Array.isArray(inputs.originalData) ? inputs.originalData : [];
const prevRow = rows.find((row) => Number(row?.年份) === prevYear && Number(row?.月份) === prevMonth && String(row?.区域 || "") === district);
