{"inputPorts":{"rows":"array","year":"number","month":"string","district":"string"},"outputPorts":{"found":"boolean","summary":"string","metrics":"object"},"script":"const rows = Array.isArray(inputs.rows) ? inputs.rows : [];
const year = Number(inputs.year || 0);
const monthRaw = String(inputs.month || '全部');
const district = String(inputs.district || '全部');
let filtered = rows;
if (year) filtered = filtered.filter((row) => Number(row?.年份) === year);
if (monthRaw && monthRaw !== '全部') filtered = filtered.filter((row) => Number(row?.月份) === Number(monthRaw));
if (district && district !== '全部') filtered = filtered.filter((row) => String(row?.区域 || '') === district);
if (!filtered.length) return { found: false, summary: "未找到匹配的数据", metrics: { 统计_数据条数: 0 } };
const totalNew = filtered.reduce((sum, row) => sum + (Number(row?.新增企业数) || 0), 0);
const totalClose = filtered.reduce((sum, row) => sum + (Number(row?.注销企业数) || 0), 0);
const totalRevenue = filtered.reduce((sum, row) => sum + (Number(row?.营业额) || 0), 0);
const avgRevenue = totalRevenue / filtered.length;
const avgSpending = filtered.reduce((sum, row) => sum + (Number(row?.人均消费) || 0), 0) / filtered.length;
const avgDelivery = filtered.reduce((sum, row) => sum + (Number(row?.外卖占比) || 0), 0) / filtered.length;
const latestRow = [...filtered].sort((a, b) => (Number(a?.年份) - Number(b?.年份)) || (Number(a?.月份) - Number(b?.月份))).at(-1) || {};
return {
  found: true,
  summary: `查询完成，共 ${filtered.length} 条记录`,
  metrics: {
    统计_新增总数: totalNew,
    统计_注销总数: totalClose,
    统计_净增长: totalNew - totalClose,
    统计_累计企业: Number(latestRow.累计企业数 || 0),
    统计_总营业额: Math.round(totalRevenue * 100) / 100,
    统计_月均营业额: Math.round(avgRevenue * 100) / 100,
    统计_人均消费: Math.round(avgSpending * 10) / 10,
    统计_外卖占比: Math.round(avgDelivery * 10) / 10,
    统计_数据条数: filtered.length,
  }
};"}

