const avgRevenue = filtered.reduce((sum, row) => sum + (Number(row?.预测营业额) || 0), 0) / filtered.length;
const avgConfidence = filtered.reduce((sum, row) => sum + (Number(row?.置信度) || 0), 0) / filtered.length;
